/**
 * Apply translations to all .checkbox-label spans based on dataset filename.
 * Called by applyTranslations() in i18n.js.
 */
export function applyDatasetLabels(lang) {
  document.querySelectorAll('.dataset').forEach(cb => {
    const val = cb.value; // e.g. "data/dados-china-ming.json"
    const key = val.replace('data/dados-', '').replace('.json', '');
    const map = DATASET_LABELS[key];
    if (!map) return;
    const label = map[lang] || map.pt;
    const span = cb.closest('.checkbox-label')?.querySelector('span');
    if (span) span.textContent = label;
  });
}
